#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends;
};

struct UserStats {
  int user_id;
  std::string username;
  int friend_count;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // 1. Create SQLite connection
    auto conn_result = sqlgen::sqlite::connect(":memory:");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // 2. Write data to database
    auto write_users = sqlgen::write(users);
    auto write_friendships = sqlgen::write(friendships);

    // 3. Execute analysis queries
    // Query 1: Mutual friends using SELF-JOIN
    auto mutual_friends_query = sqlgen::select_from<User, "u1">("username"_t1, "username"_t2, sqlgen::count().as<"mutual_friends">)
        | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user1_id"_t3)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_t3 == "user1_id"_t4)
        | sqlgen::inner_join<User, "u2">("user_id2"_t4 == "user_id"_t2)
        | sqlgen::where("user_id"_t1 < "user_id"_t2 && 
                       sqlgen::exists(sqlgen::select_from<Friendship, "f3">()
                                      .where("user1_id"_t5 == "user_id"_t1 && 
                                            "user2_id"_t5 == "user_id"_t2)))
        | sqlgen::group_by("user_id"_t1, "user_id"_t2)
        | sqlgen::having(sqlgen::count() > 0)
        | sqlgen::to<std::vector<FriendConnection>>;

    // Query 2: Users with more than average friends using nested query
    auto avg_query = sqlgen::select_from<User>("user_id"_t1)
        | sqlgen::left_join<Friendship>("user_id"_t1 == "user1_id"_t2)
        | sqlgen::group_by("user_id"_t1, "username"_t1)
        | sqlgen::select_from<User>("user_id"_t1, "username"_t1, sqlgen::count("user2_id"_t2).as<"friend_count">)
        | sqlgen::group_by("user_id"_t1, "username"_t1)
        | sqlgen::to<std::vector<UserStats>>;

    auto high_connectivity_query = sqlgen::select_from<User>("user_id"_t1, "username"_t1, sqlgen::count("user2_id"_t2).as<"friend_count">)
        | sqlgen::left_join<Friendship>("user_id"_t1 == "user1_id"_t2)
        | sqlgen::group_by("user_id"_t1, "username"_t1)
        | sqlgen::having(sqlgen::count("user2_id"_t2) > sqlgen::avg(avg_query))
        | sqlgen::order_by(sqlgen::count("user2_id"_t2).desc())
        | sqlgen::to<std::vector<UserStats>>;

    // Query 3: Friend-of-friend relationships
    auto foaf_query = sqlgen::select_from<User, "u1">("username"_t1)
        | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user1_id"_t3)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_t3 == "user1_id"_t4)
        | sqlgen::inner_join<User, "u2">("user_id2"_t4 == "user_id"_t2)
        | sqlgen::where("user_id"_t1 != "user_id"_t2 && 
                       !sqlgen::exists(sqlgen::select_from<Friendship, "f3">()
                                      .where("user1_id"_t5 == "user_id"_t1 && 
                                            "user2_id"_t5 == "user_id"_t2)))
        | sqlgen::to<std::vector<std::string>>;

    // Query 4: Friends per user with aggregation
    auto friends_per_user_query = sqlgen::select_from<User>("username"_t1, sqlgen::count("user2_id"_t2).as<"friend_count">)
        | sqlgen::left_join<Friendship>("user_id"_t1 == "user1_id"_t2)
        | sqlgen::group_by("username"_t1)
        | sqlgen::order_by(sqlgen::count("user2_id"_t2).desc())
        | sqlgen::to<std::vector<std::pair<std::string, int>>>;

    // Query 5: Same city recommendations
    auto same_city_query = sqlgen::select_from<User, "u1">("username"_t1)
        | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2 && 
                                         "user_id"_t1 != "user_id"_t2 && 
                                         !sqlgen::exists(sqlgen::select_from<Friendship, "f">()
                                                        .where("user1_id"_t3 == "user_id"_t1 && 
                                                                "user2_id"_t3 == "user_id"_t2)))
        | sqlgen::to<std::vector<std::string>>;

    // Execute all queries
    auto mutual_results = mutual_friends_query(conn);
    auto high_connectivity_results = high_connectivity_query(conn);
    auto foaf_results = foaf_query(conn);
    auto friends_per_user_results = friends_per_user_query(conn);
    auto same_city_results = same_city_query(conn);

    // Return mutual friends results as specified
    return mutual_results.value();
}

}  // namespace analyze_social_network
```

